<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  qryFestival.SQL.Text := </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;SELECT DISTINCT CompanyID FROM tblActivity ORDER BY CompanyID&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
